@Service
class FileStorageService {

    private static final Set<String> ALLOWED_EXTENSIONS = Set.of("jpg", "jpeg", "png", "gif", "webp");
    private final Path publicUploadDir = Paths.get("public", "uploads").toAbsolutePath().normalize();

    public void init() throws IOException {
        Files.createDirectories(publicUploadDir);
    }

    public Path getPublicUploadDir() {
        return publicUploadDir;
    }

    public String storeProfilePicture(MultipartFile file) throws IOException {
        if (file == null || file.isEmpty()) {
            throw new FileStorageException("File is required");
        }

        String contentType = file.getContentType();
        if (contentType == null || !contentType.toLowerCase().startsWith("image/")) {
            throw new FileStorageException("Only image files are allowed");
        }

        String originalFilename = StringUtils.cleanPath(file.getOriginalFilename() == null ? "" : file.getOriginalFilename());
        String extension = getExtension(originalFilename).toLowerCase();

        if (!ALLOWED_EXTENSIONS.contains(extension)) {
            throw new FileStorageException("Supported formats: jpg, jpeg, png, gif, webp");
        }

        String filename = UUID.randomUUID() + "." + extension;
        Path target = publicUploadDir.resolve(filename).normalize();

        if (!target.startsWith(publicUploadDir)) {
            throw new FileStorageException("Invalid file path");
        }

        try (InputStream inputStream = file.getInputStream()) {
            Files.copy(inputStream, target, StandardCopyOption.REPLACE_EXISTING);
        }

        return filename;
    }

    private String getExtension(String filename) {
        int lastDot = filename.lastIndexOf('.');
        return lastDot >= 0 ? filename.substring(lastDot + 1) : "";
    }
}

@RestController
@RequestMapping("/api/profile")
class ProfilePictureController {

    private final FileStorageService fileStorageService;

    ProfilePictureController(FileStorageService fileStorageService) {
        this.fileStorageService = fileStorageService;
    }

    @PostMapping(value = "/picture", consumes = MediaType.MULTIPART_FORM_DATA_VALUE)
    public ResponseEntity<Map<String, String>> uploadProfilePicture(
            @RequestParam("file") MultipartFile file,
            HttpServletRequest request) throws IOException {

        String storedFilename = fileStorageService.storeProfilePicture(file);
        String fileUrl = buildFileUrl(request, storedFilename);

        return ResponseEntity.status(HttpStatus.CREATED)
                .body(Map.of(
                        "message", "Profile picture uploaded successfully",
                        "fileName", storedFilename,
                        "url", fileUrl
                ));
    }

    private String buildFileUrl(HttpServletRequest request, String filename) {
        String scheme = request.getScheme();
        String serverName = request.getServerName();
        int serverPort = request.getServerPort();
        String contextPath = request.getContextPath();

        boolean defaultPort = ("http".equalsIgnoreCase(scheme) && serverPort == 80)
                || ("https".equalsIgnoreCase(scheme) && serverPort == 443);

        String portPart = defaultPort ? "" : ":" + serverPort;
        return scheme + "://" + serverName + portPart + contextPath + "/uploads/" + filename;
    }
}

